package main

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
)

func GenerateSessionToken() (string, error) {
	bytes := make([]byte, 32)
	_, err := rand.Read(bytes)
	if err != nil {
		return "", err
	}
	
	token := base64.URLEncoding.EncodeToString(bytes)
	if len(token) > 32 {
		token = token[:32]
	}
	
	return token, nil
}

func GenerateSessionTokenAlphanumeric() (string, error) {
	const charset = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	bytes := make([]byte, 32)
	_, err := rand.Read(bytes)
	if err != nil {
		return "", err
	}
	
	for i := 0; i < 32; i++ {
		bytes[i] = charset[int(bytes[i])%len(charset)]
	}
	
	return string(bytes), nil
}

func main() {
	token, err := GenerateSessionTokenAlphanumeric()
	if err != nil {
		fmt.Println("Error:", err)
		return
	}
	fmt.Println("Session Token:", token)
}